import { ImageResponse } from '@vercel/og';

export const runtime = 'nodejs';

// Placeholder for base64 injected content (mocup1.png)
const MOCUP_BASE64 = "data:image/png;base64,";

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);

    // Get dynamic data
    const name = searchParams.get('name') || 'Guest Name';
    const title = searchParams.get('title') || 'Founder';
    const company = searchParams.get('company') || 'Tech Company';
    // const industry = searchParams.get('industry') || 'Technology'; // Future use

    return new ImageResponse(
      (
        <div style={{
          width: '1200px',
          height: '1200px',
          display: 'flex',
          position: 'relative',
          fontFamily: 'sans-serif',
        }}>
          {/* Background Image (Mockup) */}
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img
            src={MOCUP_BASE64}
            width="1200"
            height="1200"
            alt="Ticket Background"
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              width: '100%',
              height: '100%',
              objectFit: 'cover'
            }}
          />

          {/* Overlay Content - Adjusted for mocup1.png layout */}
          {/* Needs calibration based on visual inspection of mocup1.png */}
          <div style={{
            position: 'absolute',
            top: '480px', // Approximate vertical center area for text
            left: '0',
            width: '100%',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            textAlign: 'center',
            padding: '0 80px', // Avoid edges
          }}>
            {/* Name */}
            <div style={{
              fontSize: 72,
              color: '#ffffff',
              fontWeight: 800,
              marginBottom: 10,
              textShadow: '0 2px 10px rgba(0,0,0,0.5)',
              textTransform: 'uppercase',
              letterSpacing: '-0.02em',
            }}>
              {name}
            </div>

            {/* Title & Company */}
            <div style={{
              fontSize: 42,
              color: '#fbbf24', // Gold color for contrast
              fontWeight: 600,
              display: 'flex',
              alignItems: 'center',
              textShadow: '0 2px 4px rgba(0,0,0,0.3)',
            }}>
              <span>{title}</span>
              {company && (
                <>
                  <span style={{ margin: '0 10px', opacity: 0.6 }}>|</span>
                  <span style={{ color: '#e5e7eb' }}>{company}</span>
                </>
              )}
            </div>
          </div>

          {/* Validation Tag / Date (Optional dynamic element bottom right) */}
          {/* <div style={{
            position: 'absolute',
            bottom: '100px',
            right: '120px',
            fontSize: 24,
            color: '#9ca3af',
            fontFamily: 'monospace'
          }}>
            VALID TICKET
          </div> */}

        </div>
      ),
      {
        width: 1200,
        height: 1200,
      }
    );
  } catch (error) {
    console.error('OG Image Generation Error:', error);
    return new Response('Failed to generate image', { status: 500 });
  }
}
